const inputItem = $input.first();
const json = inputItem.json;
const binary = inputItem.binary ?? {};
const binaryKeys = Object.keys(binary);

// Normalize sender (may be string or object)
const senderRaw = json.From ?? json.from ?? json.Sender ?? json.sender ?? null;
let sender = '未知寄件者';
if (typeof senderRaw === 'string') {
  sender = senderRaw;
} else if (senderRaw && typeof senderRaw === 'object') {
  const v = senderRaw.value;
  sender = senderRaw.text
    ?? (Array.isArray(v) && v[0] ? v[0].name + ' <' + v[0].address + '>' : null)
    ?? '未知寄件者';
}

const base = {
  gmail_id:    json.id ?? json.threadId ?? '',
  subject:     json.Subject ?? json.subject ?? '(無主旨)',
  sender,
  body:        json.Text ?? json.text ?? json.Body ?? json.body ?? '',
  received_at: json.Date ?? json.date ?? new Date().toISOString(),
};

// No attachments → one item, _done: true (skip Write Binary File)
if (binaryKeys.length === 0) {
  return [{ json: { ...base, _done: true } }];
}

// Has attachments → one item per attachment, carry binary for Write Binary File
return binaryKeys.map(key => {
  const bin = binary[key];
  return {
    json: {
      ...base,
      _done:     false,
      _filename: bin.fileName ?? bin.filename ?? key,
      _mimetype: bin.mimeType ?? null,
    },
    binary: { attachment: bin },
  };
});

const items = $input.all();
const first = items[0].json;

const emailData = {
  gmail_id:    first.gmail_id,
  subject:     first.subject,
  sender:      first.sender,
  body:        first.body,
  received_at: first.received_at,
};

const baseDir = '/Users/yang/PM_Attachments';
const attachments = items.map(item => ({
  filename:  item.json._filename,
  file_path: baseDir + '/' + item.json.gmail_id + '_' + item.json._filename,
  mime_type: item.json._mimetype,
  size:      null,
  data:      null,
}));

return [{ json: { ...emailData, attachments } }];
